const lead = $input.all()[0].json;
const name = lead.customerName || 'there';
const service = (lead.services || []).join(', ') || 'our services';
const date = lead.movingDate || 'your chosen date';

const subject = `Following up on your enquiry — ${lead.rawEmailSubject || 'LeadFlow'}`;

const html = `
<!DOCTYPE html>
<html>
<body style="background:#f4f4f8; padding: 40px 20px; font-family: -apple-system, Arial, sans-serif;">
  <div style="max-width:600px; margin:0 auto; background:white; border-radius:12px; padding:40px; box-shadow:0 2px 12px rgba(0,0,0,0.08);">
    <h2 style="color:#1a1a2e; margin-bottom:8px;">Just checking in 👋</h2>
    <p style="color:#555; font-size:16px;">Hi ${name},</p>
    <p style="color:#555; font-size:16px;">
      We wanted to follow up on your recent enquiry. We would love to help you with <strong>${service}</strong> on <strong>${date}</strong>.
    </p>
    <p style="color:#555; font-size:16px;">
      If you have any questions or are ready to proceed, just reply to this email or give us a call — we're here to help.
    </p>
    <div style="margin: 32px 0;">
      <a href="mailto:${lead.fromEmail || ''}" style="background:#6c47ff; color:white; padding:12px 28px; border-radius:8px; text-decoration:none; font-weight:600;">Reply to Us</a>
    </div>
    <p style="color:#999; font-size:13px;">You're receiving this because you made an enquiry with us. To unsubscribe, simply reply with 'unsubscribe'.</p>
  </div>
</body>
</html>`;

return [{
  json: {
    ...lead,
    followUpSubject: subject,
    followUpHtml: html
  }
}];
